const leads = $input.all();
const validadores = $('Validadores').all().map(item => item.json);

if (!validadores.length) {
  throw new Error('Nenhum validador encontrado.');
}

return leads.map((lead, index) => {
  const validador = validadores[index % validadores.length];

  return {
    json: {
      ...lead.json,
      id: validador.id,
      name: validador.name,
      number: validador.number,
      token: validador.token,
      ownerJid: validador.ownerJid,
      validador_index: index % validadores.length,
      lead_index: index + 1
    }
  };
});

const raw = $json.text || '';

const clean = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(clean);
} catch (error) {
  parsed = {
    empresa_nome: null,
    empresa_origem: null,
    handle_extraido: null,
    confianca: 'baixa',
    similaridade_nicho: 0,
    nicho_sugerido: null,
    motivo_nicho: 'Falha ao converter resposta do LLM em JSON',
    motivo: 'Falha ao converter resposta do LLM em JSON'
  };
}

return {
  json: {
    empresa_nome: parsed.empresa_nome || null,
    empresa_origem: parsed.empresa_origem || null,
    handle_extraido: parsed.handle_extraido || null,
    confianca: parsed.confianca || 'baixa',
    similaridade_nicho: Number(parsed.similaridade_nicho ?? 0),
    nicho_sugerido: parsed.nicho_sugerido|| null,
    motivo_nicho: parsed.motivo_nicho || null,
    motivo: parsed.motivo || null,

    empresa_json: $('Loop Over Items').item.json
  }
};

